import React, { useEffect, useState } from "react";
import { Button, Typography, Box, Alert, CircularProgress } from "@mui/material";
import { useNavigate } from "react-router-dom";
import api from "../../services/api";

export default function RiderDashboard() {
  const navigate = useNavigate();
  const [rider, setRider] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api
      .get("/rider/status")
      .then((res) => {
        setRider(res.data.user);
        setLoading(false);
      })
      .catch((err) => {
        console.error(err);
        setLoading(false);
      });
  }, []);

  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("role");
    navigate("/login");
  };

  if (loading) return <CircularProgress sx={{ m: 4 }} />;

  if (!rider) return <Alert severity="error">Error loading rider data</Alert>;

  if (rider.approvalStatus === "pending") {
    return (
      <Box sx={{ p: 4 }}>
        <Typography variant="h5" sx={{ mb: 2 }}>
          ⏳ Your account is pending approval by the company.
        </Typography>
        <Typography variant="body1" sx={{ mb: 2 }}>
          Please wait while an admin verifies your documents.
        </Typography>
        <Button
          variant="contained"
          sx={{ bgcolor: "black", color: "white" }}
          onClick={handleLogout}
        >
          Logout
        </Button>
      </Box>
    );
  }

  if (rider.approvalStatus === "rejected") {
    return (
      <Box sx={{ p: 4 }}>
        <Typography variant="h5" sx={{ mb: 2, color: "red" }}>
          ❌ Your account was rejected.
        </Typography>
        <Typography variant="body1" sx={{ mb: 2 }}>
          Please re-upload valid documents for review.
        </Typography>
        <Button
          variant="contained"
          sx={{ bgcolor: "black", color: "white" }}
          onClick={() => navigate("/upload-docs")}
        >
          Re-upload Documents
        </Button>
      </Box>
    );
  }

  // Approved Dashboard
  return (
    <Box sx={{ p: 4 }}>
      <Typography variant="h4" sx={{ fontWeight: "bold", mb: 2 }}>
        Rider Dashboard
      </Typography>
      <Typography variant="body1" sx={{ mb: 3 }}>
        Welcome {rider.fullName}! ✅ Your account is approved.  
        Here you can see ride requests, track trips, and manage earnings.
      </Typography>
      <Button
        variant="contained"
        sx={{ bgcolor: "black", color: "white", "&:hover": { bgcolor: "#333" } }}
        onClick={handleLogout}
      >
        Logout
      </Button>
    </Box>
  );
}
